func solve(value []int64, limit []int64) int64 {
    // Create a slice of structs to hold value and limit for each element
    elements := make([]struct {
        v, l int64
    }, len(value))
    for i := range value {
        elements[i] = struct {
            v, l int64
        }{value[i], limit[i]}
    }

    // Sort elements by value in descending order and by limit in ascending order
    sort.Slice(elements, func(i, j int) bool {
        if elements[i].v != elements[j].v {
            return elements[i].v > elements[j].v
        }
        return elements[i].l < elements[j].l
    })

    var total int64
    var activeCount int
    activeSet := make(map[int]bool)

    for _, elem := range elements {
        // Check if the element can be activated
        if activeCount < elem.l && !activeSet[elem.l] {
            total += elem.v
            activeSet[elem.l] = true
            activeCount++
        }
    }

    return total
}
